insert into documents (filename, content) values
('Politica_de_Ferias_e_Folgas.txt', 'A política de férias da CorpTech garante 30 dias corridos de férias após 12 meses de trabalho. O colaborador deve solicitar férias com 30 dias de antecedência ao gestor. Folgas compensatórias podem ser programadas mediante acordo com o time. Durante o período de férias, não há desconto salarial e benefícios permanecem ativos.'),
('Processo_de_Onboarding.txt', 'O processo de onboarding da CorpTech inclui apresentação da equipe, configuração de equipamentos e ferramenta de trabalho. Nos primeiros dias, o novo colaborador participa de sessões de integração sobre missão, valores e ferramentas internas. Há treinamentos obrigatórios de segurança da informação e políticas internas.'),
('Beneficios.txt', 'A CorpTech oferece plano de saúde corporativo, vale-refeição e vale-transporte. O plano de saúde cobre consultas e exames básicos com coparticipação reduzida. O VR é creditado mensalmente e deve ser usado em estabelecimentos parceiros. O VT é fornecido conforme distâncias do trajeto entre casa e trabalho.'),
('Codigo_de_Conduta.txt', 'O código de conduta da CorpTech exige respeito mútuo, postura ética e responsabilidade. Toda comunicação interna deve ser transparente e profissional. Assédio é proibido e denúncias são tratadas com confidencialidade. O uso de recursos da empresa deve ser adequado e seguro.'),
('Reembolso_de_Despesas.txt', 'O procedimento de reembolso exige comprovantes eletrônicos e aprovação do gestor. Despesas elegíveis incluem viagens a trabalho, material de escritório e refeições de trabalho, dentro de políticas internas. O colaborador deve submeter o pedido no sistema de reembolso em até 30 dias após a despesa. O pagamento é processado no ciclo seguinte após aprovação.');
